sql:
SELECT 
  ROUND(
    (CAST(COUNT(DISTINCT i.player_id) AS REAL) / COUNT(DISTINCT p.player_id)) * 100, 2
  ) AS avg_injury_rate
FROM players p
LEFT JOIN injuries i ON p.player_id = i.player_id;

